// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

contract FundPoolManager {
    address private owner;
    mapping(address => address) private pools;

    event PoolAdded(address pool, address rewardToken);
    event PoolRemoved(address pool);
    event TransferExecuted(address indexed to, uint256 amount);
    event FundRescued(address indexed to, uint256 amount);

    modifier onlyOwner() {
        require(msg.sender == owner, "Not the owner");
        _;
    }

    modifier onlyRegisteredPool() {
        require(pools[msg.sender] != address(0), "Unregistered pool");
        _;
    }

    constructor() {
        owner = msg.sender;
    }

    function poolsAddress(address pool) public view returns (address) {
        return pools[pool];
    }

    function addPool(address pool, address rewardToken) public onlyOwner {
        require(pool != address(0), "Invalid pool address");
        require(pools[pool] == address(0), "Pool already exists");
        pools[pool] = rewardToken;
        emit PoolAdded(pool, rewardToken);
    }

    function removePool(address pool) public onlyOwner {
        require(pool != address(0), "Invalid pool address");
        require(pools[pool] != address(0), "Pool does not exist");
        delete pools[pool];
        emit PoolRemoved(pool);
    }

    function transferTo(address payable to, uint256 amount) public onlyRegisteredPool {
        require(to != address(0), "Invalid recipient address");
        require(address(this).balance >= amount, "Insufficient balance");
        (bool sent,) = to.call{value: amount}("");
        require(sent, "Failed to send Ether");
        emit TransferExecuted(to, amount);
    }

    function rescueFund(address payable to, uint256 amount) public onlyOwner {
        require(to != address(0), "Invalid recipient address");
        require(address(this).balance >= amount, "Insufficient balance");
        (bool sent,) = to.call{value: amount}("");
        require(sent, "Failed to send Ether");
        emit FundRescued(to, amount);
    }

    receive() external payable {}

}
